mapper.select:
SELECT DISTINCT r.record_id, r.task_id, r.student_id, r.sign_time, r.sign_status, r.is_makeup
FROM attendance_record r
JOIN attendance_task t ON r.task_id = t.task_id
JOIN student s ON r.student_id = s.student_id

    AND r.task_id = #{taskId}
    AND r.student_id = #{studentId}
    AND s.class_name = #{className}

        AND EXISTS (SELECT 1 FROM team_member tm WHERE tm.student_id = s.student_id AND tm.team_id = #{teamId} AND tm.status = 1)

    AND t.teacher_id = #{teacherId}

        AND DATE(t.start_time) >= #{startDate}


        AND DATE(t.end_time) <= #{endDate}
